Hmm, one way is to add a class to the "Name" column filter (using [`filter_cellFilter`](https://mottie.github.io/tablesorter/docs/#widget-filter-cellfilter), then hide everything except that filter in the media query ([demo](https://jsfiddle.net/k8qjkL9p/3/)).

```css
@media ( max-width: 35em) {
  /* hide all filters except the name column filter */
  .tablesorter-filter-row td:not(.name) {
    display: none;
  }
  /* ... */
}
```

```js
$(function() {
  // simple reflow widget + columnSelector & stickyHeaders widgets
  $("#table2").tablesorter({
    theme: 'bootstrap',
    headerTemplate: '{content}{icon}',
    widgets: ['zebra', 'uitheme', 'reflow', 'filter'],
    widgetOptions: {
      // add "name" class to "Name" column
      filter_cellFilter : [ 'name' ],
      
      // class name added to make it responsive (class name within media query)
      reflow_className: 'ui-table-reflow',
      // header attribute containing modified header name
      reflow_headerAttrib: 'data-name',
      // data attribute added to each tbody cell
      // it contains the header cell text, visible upon reflow
      reflow_dataAttrib: 'data-title'
    }
  });
});
```

Hi @savicmi!

I modified your demo a bit... instead of applying the animation immediately after you add the row, I applied it *after* the "update" method finished processing via the callback method ([demo](https://jsfiddle.net/Mottie/h9gpqrwn/16/)):

```js
$(document).ready(function() {
  var isFirst = true;

  $(".table-liveevents").tablesorter({
    sortList: [
      [1, 0]
    ],
    ignoreCase: true,
    textExtraction: {
      '.sorter-date': function(node, table, cellIndex) {
        var dat = node.textContent.split(/\/|\s|\:/);
        var date = dat[1] + '/' + dat[0] + '/' + dat[2] + ' ' + dat[3] + ':' + dat[4];
        return new Date(date).getTime();
      }
    },
    resort: true
  });

  var data = {
    "live_ev": [{
      "id": 206622,
      "date": "28/06/2017 11:55",
      "name": "Evtimova, Dia - Dulgheru, Alexandra",
      "sport": "Tennis"
    }, {
      "id": 206553,
      "date": "28/06/2017 11:40",
      "name": "Sabanin, Yan - Matsukevitch, Denis",
      "sport": "Tennis",
    }, {
      "id": 206754,
      "date": "28/06/2017 13:05",
      "name": "Crvena Zvezda - Partizan",
      "sport": "Basketball"
    }]
  };

  function animate() {
    var $basketball = $('.table-liveevents').find('tr:has(td:contains("Basketball"))');

    if ($basketball.length > 0 && isFirst == true) {
      $basketball.addClass("highlight").one('webkitAnimationEnd mozAnimationEnd msAnimationEnd oAnimationEnd animationend', function() {
        $(this).removeClass("highlight");
      });
      isFirst = false;
    }
  }

  function addRow(data, table) {

    if (table.find('tr#r_' + data.id).length == 0) {
      var tr = document.createElement('tr');
      tr.id = 'r_' + data.id;
      tr.className = 'details';
      for (var j = 1; j <= 3; j++) {
        var td = document.createElement('td');
        td.appendChild(document.createTextNode(data[Object.keys(data)[j]]));
        tr.appendChild(td);
      }
      table.find('tbody').append(tr);
      // .trigger( 'addRows', [ $row, resort, callback ] );
      table.trigger('update', [true, animate()]);
    }
  }

  setInterval(function() {
    var i = Math.floor(Math.random() * data.live_ev.length);
    addRow(data.live_ev[i], $('.table-liveevents'));
  }, 3000);

});
```

Oddly, I tried to use the [`addRows` method](https://mottie.github.io/tablesorter/docs/#addrows) to update the internal cache, but it wasn't applying the sort. I'll have to look into that when I get some more free time. But the demo I shared above is using "update" and it appears to work as you would expect.

