I decided to make a wrapper class that has the methods I need from LDAP, so I can still use the same decorators.

    # auth.py
    from random import randint
    from flask_simpleldap import LDAP

    class LDAPContainer(object):
        def __init__(self, app=None):
            self.ldaps = []
            if app is not None:
                hosts = app.config['LDAP_HOSTS'].replace(" ", "").split(",")
                for host in hosts:
                    app.config['LDAP_HOST'] = host
                    self.ldaps.append(LDAP(app))

        def init_app(self, app):
            if app is not None:
                hosts = app.config['LDAP_HOSTS'].replace(" ", "").split(",")
                for host in hosts:
                    print "adding LDAP server: %s" % host
                    app.config['LDAP_HOST'] = host
                    self.ldaps.append(LDAP(app))

        def basic_auth_required(self, func):
            return self.ldaps[randint(0, len(self.ldaps))-1].basic_auth_required(func)

        def get_user_groups(self, user):
            return self.ldaps[randint(0, len(self.ldaps))-1].get_user_groups(user)

        @staticmethod
        def group_required(groups=None):
            return LDAP.group_required(groups)


    auth = LDAPContainer()


Then I import `auth` in my app setup. 

Does this look reasonable? I could have made it more complex by having some kind of retry against another host if the request fails.

solved with ovverriding exclude_current_instance method in rest_framework_mongoengine.validators.UniqueValidator

```
    def exclude_current_instance(self, queryset):
        """
        If an instance is being updated, then do not include
        that instance itself as a uniqueness conflict.
        """
        if self.instance is not None:
            return queryset.filter(pk__ne=self.instance.pk)
        return queryset

